#include "controller.h"

static void controller_set_safe_vent(controller_t *controller)
{
    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_vent(controller);
    controller->has_valid_pressure = false;
    controller->last_pressure_kpa = 0;
    controller->last_pressure_ms = 0U;
    controller->has_valid_door = false;
    controller->door_closed = false;
    controller->last_door_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .compressor_on = false,
        .vent_open = true,
        .state = CONTROLLER_STATE_SAFE_VENT,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_VENT),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    /* Check for stale sensor data - either sensor being stale forces SAFE_VENT */
    uint32_t now_ms = input.now_ms;
    bool door_stale = !controller->has_valid_door || (now_ms - controller->last_door_ms > CONTROLLER_SENSOR_TIMEOUT_MS);
    bool pressure_stale = !controller->has_valid_pressure || (now_ms - controller->last_pressure_ms > CONTROLLER_SENSOR_TIMEOUT_MS);

    if (door_stale || pressure_stale) {
        /* Either sensor is stale - go to safe vent */
        controller_set_safe_vent(controller);
        output.timed_out = true;
    } else {
        /* Both sensors are valid - apply control policy */
        bool previous_compressor_on = controller->compressor_on;
        bool previous_vent_open = controller->vent_open;

        if (input.kind == CONTROLLER_INPUT_DOOR_OPEN) {
            /* Door is open - safe state: compressor off, vent open */
            controller->has_valid_door = true;
            controller->door_closed = false;
            controller->last_door_ms = now_ms;
            controller_set_safe_vent(controller);
        } else if (input.kind == CONTROLLER_INPUT_DOOR_CLOSED) {
            /* Door is closed - apply pressure-based control */
            controller->has_valid_door = true;
            controller->door_closed = true;
            controller->last_door_ms = now_ms;

            if (controller->has_valid_pressure) {
                int current_pressure = input.pressure_kpa;
                if (current_pressure < CONTROLLER_PRESSURE_LOW_THRESHOLD) {
                    /* Low pressure - pressurize */
                    controller->compressor_on = true;
                    controller->vent_open = false;
                    controller->state = CONTROLLER_STATE_PRESSURIZING;
                } else if (current_pressure > CONTROLLER_PRESSURE_HIGH_THRESHOLD) {
                    /* High pressure - relieve */
                    controller->compressor_on = false;
                    controller->vent_open = true;
                    controller->state = CONTROLLER_STATE_RELIEVING;
                } else {
                    /* In band (40-60) - hold previous safe output */
                    if (previous_compressor_on && !previous_vent_open) {
                        controller->compressor_on = true;
                        controller->vent_open = false;
                        controller->state = CONTROLLER_STATE_HOLDING;
                    } else if (!previous_compressor_on && previous_vent_open) {
                        controller->compressor_on = false;
                        controller->vent_open = true;
                        controller->state = CONTROLLER_STATE_HOLDING;
                    } else {
                        /* No change needed - keep current state */
                    }
                }
            } else {
                /* Pressure not valid yet - stay in safe vent until pressure is seen */
                controller_set_safe_vent(controller);
            }
        } else if (input.kind == CONTROLLER_INPUT_PRESSURE) {
            /* Pressure updated but door status unknown - stay in safe vent */
            controller->has_valid_pressure = true;
            controller->last_pressure_kpa = input.pressure_kpa;
            controller->last_pressure_ms = now_ms;
            controller_set_safe_vent(controller);
        } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
            /* Timeout detected - safe vent */
            controller_set_safe_vent(controller);
        } else if (input.kind == CONTROLLER_INPUT_INVALID_PRESSURE || input.kind == CONTROLLER_INPUT_INVALID_DOOR) {
            /* Invalid input - safe vent */
            controller_set_safe_vent(controller);
        }
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_compressor_on != controller->compressor_on) ||
                      (previous_vent_open != controller->vent_open) ||
                      (controller->state != CONTROLLER_STATE_SAFE_VENT &&
                       previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_PRESSURIZING:
        return "STATE PRESSURIZING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_RELIEVING:
        return "STATE RELIEVING";
    case CONTROLLER_STATE_SAFE_VENT:
    default:
        return "STATE SAFE_VENT";
    }
}

