        } else if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
            /* Timeout detected - safe vent */
            controller_set_safe_vent(controller);
        } else if (input.kind == CONTROLLER_INPUT_INVALID_PRESSURE || input.kind == CONTROLLER_INPUT_INVALID_DOOR) {
            /* Invalid input - safe vent */
            controller_set_safe_vent(controller);
        }
    }

    output.compressor_on = controller->compressor_on;
    output.vent_open = controller->vent_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    /* Check if output changed */
    bool compressor_changed = (previous_compressor_on != controller->compressor_on);
    bool vent_changed = (previous_vent_open != controller->vent_open);
    bool state_changed = false;

    if (controller->state != CONTROLLER_STATE_SAFE_VENT) {
        /* Only consider state change if we moved to a non-safe-vent state */
        state_changed = true;
    }

    output.changed = compressor_changed || vent_changed || state_changed;

    return output;
}

